def select_next_node(current, destination, trucks, unvisited):
    min_total_distance = float('inf')
    next_destination = None
    p = 3 # Choose any value for p, not necessarily just 1 or 2

    for i, coord in enumerate(unvisited):
        total_distance = 0
        for truck in trucks:
            total_distance += np.power(np.linalg.norm(truck - coord), p)

